func _init():
	print("Generating tileset...")

	# Create a 48x16 image
	var img = Image.create(48, 16, false, Image.FORMAT_RGBA8)

	# Tile 0: Floor (e.g., dark gray)
	for x in range(0, 16):
		for y in range(0, 16):
			img.set_pixel(x, y, Color(0.2, 0.2, 0.2))

	# Tile 1: Wall (e.g., light gray)
	for x in range(16, 32):
		for y in range(0, 16):
			img.set_pixel(x, y, Color(0.6, 0.6, 0.6))

	# Tile 2: Door (e.g., brown)
	for x in range(32, 48):
		for y in range(0, 16):
			img.set_pixel(x, y, Color(0.6, 0.3, 0.1))

	img.save_png("res://assets/tiles.png")

	var texture = ImageTexture.create_from_image(img)

	var tileset = TileSet.new()
	tileset.tile_size = Vector2i(16, 16)

	var source = TileSetAtlasSource.new()
	source.texture = texture
	source.texture_region_size = Vector2i(16, 16)

	# Create tiles
	source.create_tile(Vector2i(0, 0)) # Floor
	source.create_tile(Vector2i(1, 0)) # Wall
	source.create_tile(Vector2i(2, 0)) # Door

	tileset.add_source(source, 0) # source_id 0? Wait, the requirements say "addressable as source_id 0 (floor), 1 (wall), and 2 (door)"
	# Ah! The requirement says: "exposes at least three logical tiles addressable as source_id 0 (floor), 1 (wall), and 2 (door)"
	# So we need 3 separate sources, or one source with ID 0, one with ID 1, one with ID 2.

	# Let's create 3 separate sources
	var img0 = Image.create(16, 16, false, Image.FORMAT_RGBA8)
	img0.fill(Color(0.2, 0.2, 0.2))
	img0.save_png("res://assets/floor.png")
	var tex0 = ImageTexture.create_from_image(img0)
	var src0 = TileSetAtlasSource.new()
	src0.texture = tex0
	src0.texture_region_size = Vector2i(16, 16)
	src0.create_tile(Vector2i(0, 0))
	tileset.add_source(src0, 0)

	var img1 = Image.create(16, 16, false, Image.FORMAT_RGBA8)
	img1.fill(Color(0.6, 0.6, 0.6))
	img1.save_png("res://assets/wall.png")
	var tex1 = ImageTexture.create_from_image(img1)
	var src1 = TileSetAtlasSource.new()
	src1.texture = tex1
	src1.texture_region_size = Vector2i(16, 16)
	src1.create_tile(Vector2i(0, 0))
	tileset.add_source(src1, 1)

	var img2 = Image.create(16, 16, false, Image.FORMAT_RGBA8)
	img2.fill(Color(0.6, 0.3, 0.1))
	img2.save_png("res://assets/door.png")
	var tex2 = ImageTexture.create_from_image(img2)
	var src2 = TileSetAtlasSource.new()
	src2.texture = tex2
	src2.texture_region_size = Vector2i(16, 16)
	src2.create_tile(Vector2i(0, 0))
	tileset.add_source(src2, 2)

	ResourceSaver.save(tileset, "res://tilesets/dungeon.tres")
	print("Tileset saved.")
	quit()

